+template <typename T>
+struct Relu2 {
+  static const bool kIsHeavy = false;
+
+  CUTLASS_HOST_DEVICE
+  T operator()(T threshold, T value) const {
+    ReLu<T> relu_op;
+    multiplies<T> mul;
+    T val = relu_op(threshold, value);
+    return mul(val, val);
+  }
+
+  CUTLASS_HOST_DEVICE
+  T operator()(T value) const {
+    ReLu<T> relu_op;
+    multiplies<T> mul;
+    T val = relu_op(value);
+    return mul(val, val);
+  }
+};
